English:
process (HCOUNT) begin
if (HCOUNT >= "1010100101" and HCOUNT <= "1011101000") then
HSYNC_IN <= '0';
else
HSYNC_IN <= '1';
end if;

if (HCOUNT <= "1000000000") then
DISP_H <='1';
else
DISP_H <='0';
end if;
end process;

process (CLK,RESET) begin
if (RESET = '1') then
HCOUNT <= "0000000000";
VCOUNT <= "000000000";
elsif (CLK'event and CLK='1') then
if ( HCOUNT = "1110001101" ) then --909
HCOUNT <= "0000000000";
if (VCOUNT = "100000101") then --261
VCOUNT <= "000000000";
else
VCOUNT <= VCOUNT + '1';
end if;
else
HCOUNT <= HCOUNT + '1' ;
end if;

end if;
end process;

